uniform 	vec4 hlslcc_mtx4x4unity_ObjectToWorld[4];
uniform 	vec4 hlslcc_mtx4x4unity_MatrixVP[4];
in highp vec4 in_POSITION0;
in highp vec2 in_TEXCOORD0;
out highp vec2 vs_TEXCOORD0;
vec4 u_xlat0;
vec4 u_xlat1;
void main()
{
    vs_TEXCOORD0.xy = in_TEXCOORD0.xy;
    u_xlat0 = in_POSITION0.yyyy * hlslcc_mtx4x4unity_ObjectToWorld[1];
    u_xlat0 = hlslcc_mtx4x4unity_ObjectToWorld[0] * in_POSITION0.xxxx + u_xlat0;
    u_xlat0 = hlslcc_mtx4x4unity_ObjectToWorld[2] * in_POSITION0.zzzz + u_xlat0;
    u_xlat0 = u_xlat0 + hlslcc_mtx4x4unity_ObjectToWorld[3];
    u_xlat1 = u_xlat0.yyyy * hlslcc_mtx4x4unity_MatrixVP[1];
    u_xlat1 = hlslcc_mtx4x4unity_MatrixVP[0] * u_xlat0.xxxx + u_xlat1;
    u_xlat1 = hlslcc_mtx4x4unity_MatrixVP[2] * u_xlat0.zzzz + u_xlat1;
    gl_Position = hlslcc_mtx4x4unity_MatrixVP[3] * u_xlat0.wwww + u_xlat1;
    return;
}


#version 300 es

precision highp float;
precision highp int;
#define HLSLCC_ENABLE_UNIFORM_BUFFERS 0
#if HLSLCC_ENABLE_UNIFORM_BUFFERS
#define UNITY_UNIFORM
#else
#define UNITY_UNIFORM uniform
#endif
#define UNITY_SUPPORTS_UNIFORM_LOCATION 0
#if UNITY_SUPPORTS_UNIFORM_LOCATION
#define UNITY_LOCATION(x) layout(location = x)
#define UNITY_BINDING(x) layout(binding = x, std140)
#else
#define UNITY_LOCATION(x)
#define UNITY_BINDING(x) layout(std140)
#endif
uniform 	mediump vec4 _FollowerColor;
uniform 	vec4 _LineShapeTex_ST;
uniform 	float _FollowerAlpha;
uniform 	float _FollowerEmission;
uniform 	float _FollowerSpacing;
uniform 	float _FollowerLength;
uniform 	float _FollowerSoftness;
uniform 	float _LineWidth;
uniform 	float _LineSoftness;
uniform 	mediump vec4 _RoadColor;
uniform 	mediump vec4 _RoadHighlightColor;
uniform 	mediump vec4 _RoadEdgeColor;
uniform 	mediump vec4 _RoadInnerLineColor;
uniform 	float _RoadEdgeWidth;
uniform 	float _RoadInnerLineOffset;
uniform 	float _RoadInnerLineWidth;
uniform 	float _RoadAlpha;
uniform 	float _RoadLength;
uniform 	float _ClosedLoop;
uniform 	float _FollowerOffset;
uniform 	float _RevealProgress;
UNITY_LOCATION(0) uniform mediump sampler2D _LineShapeTex;
in highp vec2 vs_TEXCOORD0;
layout(location = 0) out mediump vec4 SV_Target0;
vec2 u_xlat0;
bvec4 u_xlatb0;
vec4 u_xlat1;
vec3 u_xlat2;
vec3 u_xlat3;
mediump vec4 u_xlat16_3;
mediump float u_xlat16_4;
vec3 u_xlat5;
vec2 u_xlat6;
bool u_xlatb6;
vec3 u_xlat7;
float u_xlat9;
float u_xlat12;
bool u_xlatb12;
vec2 u_xlat13;
float u_xlat18;
float u_xlat19;
float u_xlat20;
void main()
{
    u_xlat0.x = max(_FollowerSpacing, 0.00999999978);
    u_xlat6.x = max(u_xlat0.x, _RoadLength);
    u_xlat6.x = u_xlat6.x / u_xlat0.x;
    u_xlat6.x = roundEven(u_xlat6.x);
    u_xlat6.x = max(u_xlat6.x, 1.0);
    u_xlat6.x = _RoadLength / u_xlat6.x;
    u_xlat6.x = max(u_xlat6.x, 0.00999999978);
    u_xlat6.x = (-u_xlat0.x) + u_xlat6.x;
    u_xlatb12 = _ClosedLoop>=0.5;
    u_xlat12 = u_xlatb12 ? 1.0 : float(0.0);
    u_xlat0.x = u_xlat12 * u_xlat6.x + u_xlat0.x;
    u_xlat6.x = vs_TEXCOORD0.y + (-_FollowerOffset);
    u_xlat0.x = u_xlat6.x / u_xlat0.x;
    u_xlat0.x = fract(u_xlat0.x);
    u_xlat6.xy = vec2(_FollowerLength, _FollowerAlpha);
    u_xlat6.xy = clamp(u_xlat6.xy, 0.0, 1.0);
    u_xlat18 = (-u_xlat6.x) + 1.0;
    u_xlat1.x = (-u_xlat18) * 0.5 + u_xlat0.x;
    u_xlat7.x = max(u_xlat6.x, 9.99999975e-05);
    u_xlat1.y = u_xlat1.x / u_xlat7.x;
    u_xlat1.y = clamp(u_xlat1.y, 0.0, 1.0);
    u_xlat13.x = vs_TEXCOORD0.x + -0.5;
    u_xlat19 = max(_LineWidth, 9.99999975e-05);
    u_xlat13.x = u_xlat13.x / u_xlat19;
    u_xlat1.x = u_xlat13.x + 0.5;
    u_xlat13.xy = (-vec2(_LineSoftness, _FollowerSoftness)) + vec2(1.0, 1.0);
    u_xlat2.xy = (-u_xlat13.xy) + u_xlat1.xy;
    u_xlat13.xy = (-u_xlat13.xy) + vec2(1.0, 1.0);
    u_xlat13.xy = vec2(1.0, 1.0) / u_xlat13.xy;
    u_xlat13.xy = u_xlat13.xy * u_xlat2.xy;
    u_xlat13.xy = clamp(u_xlat13.xy, 0.0, 1.0);
    u_xlat2.xy = u_xlat13.xy * vec2(-2.0, -2.0) + vec2(3.0, 3.0);
    u_xlat13.xy = u_xlat13.xy * u_xlat13.xy;
    u_xlat13.xy = (-u_xlat2.xy) * u_xlat13.xy + vec2(1.0, 1.0);
    u_xlat2.xy = vec2(1.0, 1.0) / vec2(_LineSoftness, _FollowerSoftness);
    u_xlat2.xy = u_xlat1.xy * u_xlat2.xy;
    u_xlat2.xy = clamp(u_xlat2.xy, 0.0, 1.0);
    u_xlat1.xy = u_xlat1.xy * _LineShapeTex_ST.xy + _LineShapeTex_ST.zw;
    u_xlat16_3 = texture(_LineShapeTex, u_xlat1.xy);
    u_xlat1.xy = u_xlat2.xy * vec2(-2.0, -2.0) + vec2(3.0, 3.0);
    u_xlat2.xy = u_xlat2.xy * u_xlat2.xy;
    u_xlat1.xy = u_xlat1.xy * u_xlat2.xy;
    u_xlat1.xy = u_xlat13.xy * u_xlat1.xy;
    u_xlat1.xy = clamp(u_xlat1.xy, 0.0, 1.0);
    u_xlat16_4 = max(u_xlat16_3.z, u_xlat16_3.y);
    u_xlat16_4 = max(u_xlat16_3.x, u_xlat16_4);
    u_xlat16_4 = max(u_xlat16_3.w, u_xlat16_4);
    u_xlat1.x = u_xlat1.x * u_xlat16_4;
    u_xlat6.x = u_xlat18 * 0.5 + u_xlat6.x;
    u_xlat18 = u_xlat18 * 0.5;
    u_xlatb0.w = u_xlat0.x>=u_xlat18;
    u_xlatb0.x = u_xlat6.x>=u_xlat0.x;
    u_xlat0.x = u_xlatb0.x ? float(1.0) : 0.0;
    u_xlat0.y = u_xlatb0.w ? float(1.0) : 0.0;
;
    u_xlat0.x = u_xlat0.x * u_xlat0.y;
    u_xlat0.x = u_xlat0.x * u_xlat1.x;
    u_xlat0.x = u_xlat1.y * u_xlat0.x;
    u_xlat0.x = u_xlat6.y * u_xlat0.x;
    u_xlat6.x = max(_RoadLength, 9.99999975e-05);
    u_xlat6.x = vs_TEXCOORD0.y / u_xlat6.x;
    u_xlatb6 = _RevealProgress>=u_xlat6.x;
    u_xlat6.x = u_xlatb6 ? 1.0 : float(0.0);
    u_xlat0.x = u_xlat6.x * u_xlat0.x;
    u_xlat12 = u_xlat0.x;
    u_xlat12 = clamp(u_xlat12, 0.0, 1.0);
    u_xlat18 = vs_TEXCOORD0.x;
    u_xlat18 = clamp(u_xlat18, 0.0, 1.0);
    u_xlat1.xy = vec2(u_xlat18) + (-vec2(_RoadEdgeWidth, _RoadInnerLineOffset));
    u_xlat1.y = abs(u_xlat1.y) + (-_RoadInnerLineWidth);
    u_xlat1.xy = u_xlat1.xy * vec2(40.0, 83.3333359);
    u_xlat1.xy = clamp(u_xlat1.xy, 0.0, 1.0);
    u_xlat13.x = u_xlat1.y * -2.0 + 3.0;
    u_xlat7.x = u_xlat1.y * u_xlat1.y;
    u_xlat7.x = (-u_xlat13.x) * u_xlat7.x + 1.0;
    u_xlat13.x = (-_RoadInnerLineOffset) + 1.0;
    u_xlat13.x = u_xlat18 + (-u_xlat13.x);
    u_xlat13.x = abs(u_xlat13.x) + (-_RoadInnerLineWidth);
    u_xlat13.x = u_xlat13.x * 83.3333359;
    u_xlat13.x = clamp(u_xlat13.x, 0.0, 1.0);
    u_xlat19 = u_xlat13.x * -2.0 + 3.0;
    u_xlat13.x = u_xlat13.x * u_xlat13.x;
    u_xlat7.x = (-u_xlat19) * u_xlat13.x + u_xlat7.x;
    u_xlat7.x = u_xlat7.x + 1.0;
    u_xlat7.x = clamp(u_xlat7.x, 0.0, 1.0);
    u_xlat7.x = u_xlat7.x * 0.850000024;
    u_xlat2.xyz = (-_RoadColor.xyz) + _RoadHighlightColor.xyz;
    u_xlat3.xyz = vec3(u_xlat18) + vec3(-0.99000001, -1.0, -0.5);
    u_xlat18 = u_xlat18 * 100.0;
    u_xlat18 = min(u_xlat18, 1.0);
    u_xlat13.x = -abs(u_xlat3.z) * 2.0 + 1.0;
    u_xlat13.x = u_xlat13.x * 0.180000007;
    u_xlat2.xyz = u_xlat13.xxx * u_xlat2.xyz + _RoadColor.xyz;
    u_xlat5.xyz = (-u_xlat2.xyz) + _RoadInnerLineColor.xyz;
    u_xlat7.xyz = u_xlat7.xxx * u_xlat5.xyz + u_xlat2.xyz;
    u_xlat2.xyz = (-u_xlat7.xyz) + _RoadEdgeColor.xyz;
    u_xlat20 = u_xlat1.x * -2.0 + 3.0;
    u_xlat1.x = u_xlat1.x * u_xlat1.x;
    u_xlat1.x = (-u_xlat20) * u_xlat1.x + 1.0;
    u_xlat20 = (-u_xlat3.y) + (-_RoadEdgeWidth);
    u_xlat3.x = u_xlat3.x * 100.000099;
    u_xlat3.x = max(u_xlat3.x, 0.0);
    u_xlat20 = u_xlat20 * 40.0;
    u_xlat20 = clamp(u_xlat20, 0.0, 1.0);
    u_xlat9 = u_xlat20 * -2.0 + 3.0;
    u_xlat20 = u_xlat20 * u_xlat20;
    u_xlat1.x = (-u_xlat9) * u_xlat20 + u_xlat1.x;
    u_xlat1.x = u_xlat1.x + 1.0;
    u_xlat1.x = clamp(u_xlat1.x, 0.0, 1.0);
    u_xlat1.xyz = u_xlat1.xxx * u_xlat2.xyz + u_xlat7.xyz;
    u_xlat2.xyz = _FollowerColor.xyz * vec3(vec3(_FollowerEmission, _FollowerEmission, _FollowerEmission)) + (-u_xlat1.xyz);
    u_xlat1.xyz = vec3(u_xlat12) * u_xlat2.xyz + u_xlat1.xyz;
    u_xlat12 = u_xlat18 * -2.0 + 3.0;
    u_xlat18 = u_xlat18 * u_xlat18;
    u_xlat12 = u_xlat18 * u_xlat12;
    u_xlat18 = u_xlat3.x * -2.0 + 3.0;
    u_xlat2.x = u_xlat3.x * u_xlat3.x;
    u_xlat18 = (-u_xlat18) * u_xlat2.x + 1.0;
    u_xlat12 = u_xlat18 * u_xlat12;
    u_xlat12 = clamp(u_xlat12, 0.0, 1.0);
    u_xlat6.x = u_xlat6.x * u_xlat12;
    u_xlat1.w = u_xlat6.x * _RoadAlpha + u_xlat0.x;
    u_xlat1.w = clamp(u_xlat1.w, 0.0, 1.0);
    SV_Target0 = u_xlat1;
    return;
}
